export async function loader({ request, params, context }: Route.LoaderArgs) {
  const url = getURLWithCorrectScheme(request);
  const token = url.searchParams.get("token") ?? "";
  const mockId = context.get(mockIdMiddlewareContext).mockId;
  const rollbar = getRollbar();

  const renderToken = process.env["PAY_API_RENDER_TOKEN"];

  if (!renderToken) {
    rollbar.error(new Error("PAY_API_RENDER_TOKEN is not set"));
    throw data("PAY_API_RENDER_TOKEN is not set", {
      status: 500,
    });
  }

  const response = await fetch(
    `https://admin.anedot.com/admin/vip_configurations/${params.vipConfigId}`,
    {
      headers: {
        "X-Token": token,
        ...(import.meta.env.MODE === "staging" && { mockId }),
      },
    },
  );

  if (!response.ok) {
    if (response.status === 499) {
      return;
    }

    if (response.status === 401 || response.status === 404) {
      return redirect("/");
    }

    rollbar.error(new Error("Failed to fetch VIP configuration"), {
      response,
    });
    throw data("Failed to fetch VIP configuration", {
      status: response.status,
    });
  }

  if (!response.headers.get("Content-Type")?.includes("application/json")) {
    return redirect("/");
  }

  const vipConfiguration: VipConfiguration = await response.json();

  if (vipConfiguration.status === "inactive") {
    return redirect("/");
  }

  return {
    vipConfiguration,
    renderToken,
    queryParams: url.search,
  };
}

